SELECT 
FROM t_voting_execution_package
WHERE package_id = #{packageId} AND tenant_id = #{tenantId}

SELECT r.roster_id, r.room_id, r.building_id, r.build_area AS certified_area, op.opid, op.uid, op.is_voting_delegate FROM c_property_roster r LEFT JOIN c_owner_property op ON op.tenant_id = r.tenant_id AND op.room_id = r.room_id AND op.verify_status = 'VERIFIED' AND op.superseded_at IS NULL WHERE r.tenant_id = #{tenantId} AND r.status = 'ACTIVE'
AND r.building_id = #{scopeReferenceId}
ORDER BY r.building_id, r.room_id, op.opid

SELECT r.roster_id, r.room_id, r.building_id, r.build_area AS certified_area, op.opid, op.uid, op.is_voting_delegate FROM c_property_roster r LEFT JOIN c_owner_property op ON op.tenant_id = r.tenant_id AND op.room_id = r.room_id AND op.verify_status = 'VERIFIED' AND op.superseded_at IS NULL WHERE r.tenant_id = #{tenantId} AND r.status = 'ACTIVE' AND r.room_id IN
#{roomId}
ORDER BY r.building_id, r.room_id, op.opid

mapper.insert:
INSERT INTO t_voting_electorate_snapshot (
    package_id, tenant_id, scope, scope_reference_id,
    total_area, total_owner_count, item_count, aggregate_hash, frozen_at
) VALUES (
    #{packageId}, #{tenantId}, #{scope}, #{scopeReferenceId},
    #{totalArea}, #{totalOwnerCount}, #{itemCount}, #{aggregateHash}, #{frozenAt}
)

mapper.select:
SELECT i.snapshot_item_id, i.snapshot_id, i.roster_id, i.room_id, i.building_id,
       i.certified_area, i.representative_opid, i.representative_uid,
       i.co_owner_uids::text AS co_owner_uids_json, i.row_hash
FROM t_voting_execution_package p
INNER JOIN t_voting_electorate_item_snapshot i
        ON i.snapshot_id = p.electorate_snapshot_id
WHERE p.package_id = #{packageId}
  AND p.tenant_id = #{tenantId}
  AND i.representative_opid = #{opid}

SELECT i.snapshot_item_id
FROM t_voting_execution_package p
INNER JOIN t_voting_electorate_item_snapshot i
        ON i.snapshot_id = p.electorate_snapshot_id
WHERE p.package_id = #{packageId}
  AND p.tenant_id = #{tenantId}
  AND i.snapshot_item_id = #{electorateItemId}
FOR UPDATE

mapper.insert:
INSERT INTO t_voting_delivery_record (
    package_id, electorate_item_id, tenant_id, delivery_channel,
    delivery_method, evidence_hash, delivered_by_user_id, delivered_at
) VALUES (
    #{packageId}, #{electorateItemId}, #{tenantId}, #{deliveryChannel},
    #{deliveryMethod}, #{evidenceHash}, #{deliveredByUserId}, #{deliveredAt}
)

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM t_voting_delivery_record
    WHERE package_id = #{packageId}
      AND tenant_id = #{tenantId}
      AND electorate_item_id = #{electorateItemId}
      AND delivery_channel = #{deliveryChannel}
)

mapper.update:
UPDATE t_voting_ballot_record
SET valid_flag = 0,
    invalid_reason = #{invalidReason},
    invalidated_at = #{invalidatedAt}
WHERE ballot_id = #{ballotId}
  AND valid_flag = 1

mapper.select:
SELECT COUNT(*)
FROM t_voting_execution_audit
WHERE package_id = #{packageId}
  AND tenant_id = #{tenantId}
  AND event_type = #{eventType}
